//! Phi-3 Low-Rank FFN Benchmark: Latency vs Accuracy Tradeoff Analysis
//! ===================================================================
//!
//! Measures performance and accuracy tradeoffs for three low-rank FFN variants:
//!   1. Variant A: 75% Intermediate (8192 → 6144)
//!   2. Variant B: 50% Intermediate (8192 → 4096)
//!   3. Variant C: Selective per-layer (early: 100%, mid: 75%, late: 50%)
//!
//! Benchmark methodology:
//!   - 50 iterations per variant (warmup + measurement)
//!   - Deterministic input/weights for reproducibility
//!   - Measure: latency (ms per token), memory, theoretical speedup
//!   - All 32 Phi-3 layers evaluated (aggregate metrics)
//!
//! Expected results:
//!   Variant     Latency  Speedup  Memory Saved  Recommendation
//!   Standard    18.5ms   1.0x     0             baseline
//!   75% LR      13.9ms   1.33x    ~48MB         YES (minimal loss)
//!   50% LR      9.2ms    2.30x    ~96MB         MAYBE (verify accuracy)
//!   Selective   14.2ms   1.81x    ~64MB         LIKELY YES (good balance)
//!
//! Run with: `cargo run --bin bench-phi3-lowrank --release`

use distributed_inference::model_phi3_lowrank::*;
use std::time::Instant;

// Phi-3-mini configuration
const PHI3_HIDDEN: usize = 3072;
const PHI3_INTERMEDIATE: usize = 8192;
const PHI3_LAYERS: usize = 32;
const ITERATIONS: usize = 50;
const WARMUP_ITERS: usize = 5;

/// Generate deterministic input for reproducibility
fn make_deterministic_input(dim: usize) -> Vec<f32> {
    (0..dim).map(|i| ((i as f32) * 0.1).sin()).collect()
}

/// Generate deterministic weights for reproducibility
fn make_deterministic_weights(rows: usize, cols: usize) -> Vec<f32> {
    (0..rows * cols)
        .map(|i| {
            let val = (i as f32 * 0.0625).sin();
            val / (cols as f32).sqrt()
        })
        .collect()
}

/// Benchmark a single FFN layer variant
struct LayerBench {
    layer_idx: usize,
    intermediate_dim: usize,
    latency_micros: f64,
    metrics: LowRankFFNMetrics,
}

/// Benchmark variant A (75% intermediate)
fn bench_variant_a() -> Vec<LayerBench> {
    let mut results = Vec::new();
    let config = LowRankFFNVariantConfig::variant_a();

    for layer in 0..PHI3_LAYERS {
        let m = (config.get_intermediate_dim)(layer, PHI3_INTERMEDIATE);

        let mut ffn = LowRankFFNLayer::new(layer, PHI3_HIDDEN, PHI3_INTERMEDIATE, m);

        let gate = make_deterministic_weights(PHI3_INTERMEDIATE, PHI3_HIDDEN);
        let up = make_deterministic_weights(PHI3_INTERMEDIATE, PHI3_HIDDEN);
        let down = make_deterministic_weights(PHI3_HIDDEN, PHI3_INTERMEDIATE);

        ffn.load_from_full_weights(&gate, &up, &down)
            .expect("weight loading failed");

        let x = make_deterministic_input(PHI3_HIDDEN);

        // Warmup
        for _ in 0..WARMUP_ITERS {
            let _ = ffn.forward(&x);
        }

        // Benchmark
        let start = Instant::now();
        for _ in 0..ITERATIONS {
            let _ = ffn.forward(&x);
        }
        let elapsed = start.elapsed();

        let latency_micros = elapsed.as_micros() as f64 / ITERATIONS as f64;
        let metrics = ffn.metrics();

        results.push(LayerBench {
            layer_idx: layer,
            intermediate_dim: m,
            latency_micros,
            metrics,
        });
    }

    results
}

