/// Benchmark standard Phi-3 FFN (baseline)
fn bench_standard() -> Vec<LayerBench> {
    let mut results = Vec::new();

    for layer in 0..PHI3_LAYERS {
        let mut ffn =
            LowRankFFNLayer::new(layer, PHI3_HIDDEN, PHI3_INTERMEDIATE, PHI3_INTERMEDIATE);

        let gate = make_deterministic_weights(PHI3_INTERMEDIATE, PHI3_HIDDEN);
        let up = make_deterministic_weights(PHI3_INTERMEDIATE, PHI3_HIDDEN);
        let down = make_deterministic_weights(PHI3_HIDDEN, PHI3_INTERMEDIATE);

        ffn.load_from_full_weights(&gate, &up, &down)
            .expect("weight loading failed");

        let x = make_deterministic_input(PHI3_HIDDEN);

        // Warmup
        for _ in 0..WARMUP_ITERS {
            let _ = ffn.forward(&x);
        }

        // Benchmark
        let start = Instant::now();
        for _ in 0..ITERATIONS {
            let _ = ffn.forward(&x);
        }
        let elapsed = start.elapsed();

        let latency_micros = elapsed.as_micros() as f64 / ITERATIONS as f64;
        let metrics = ffn.metrics();

        results.push(LayerBench {
            layer_idx: layer,
            intermediate_dim: PHI3_INTERMEDIATE,
            latency_micros,
            metrics,
        });
    }

    results
}

/// Aggregate statistics from benchmark results
struct AggregateStats {
    variant_name: String,
    avg_latency_micros: f64,
    min_latency_micros: f64,
    max_latency_micros: f64,
    total_memory_saved_mb: f64,
    aggregate_speedup: f32,
    avg_compression_ratio: f32,
}

impl AggregateStats {
    fn from_benches(name: &str, benches: &[LayerBench]) -> Self {
        let latencies: Vec<f64> = benches.iter().map(|b| b.latency_micros).collect();
        let avg_latency = latencies.iter().sum::<f64>() / latencies.len() as f64;
        let min_latency = latencies.iter().copied().fold(f64::INFINITY, f64::min);
        let max_latency = latencies.iter().copied().fold(0.0, f64::max);
        let _total_latency = latencies.iter().sum::<f64>();

        let memory_saved: f64 = benches
            .iter()
            .map(|b| b.metrics.memory_savings() as f64 / 1e6)
            .sum();
        let avg_compression: f32 = benches
            .iter()
            .map(|b| b.metrics.compression_ratio)
            .sum::<f32>()
            / benches.len() as f32;
        let avg_speedup: f32 = benches
            .iter()
            .map(|b| b.metrics.speedup_factor)
            .sum::<f32>()
            / benches.len() as f32;

        AggregateStats {
            variant_name: name.to_string(),
            avg_latency_micros: avg_latency,
            min_latency_micros: min_latency,
            max_latency_micros: max_latency,
            total_memory_saved_mb: memory_saved,
            aggregate_speedup: avg_speedup,
            avg_compression_ratio: avg_compression,
        }
    }

    fn display_header() {
        println!(
            "\n{:<15} {:<15} {:<12} {:<12} {:<12} {:<12} {:<15}",
            "Variant",
            "Avg Latency",
            "Speedup",
            "Compression",
            "Memory Saved",
            "Min/Max μs",
            "Recommendation"
        );
        println!(
            "{:-<15} {:-<15} {:-<12} {:-<12} {:-<12} {:-<12} {:-<15}",
            "", "", "", "", "", "", ""
        );
    }

    fn display(&self, baseline_latency: f64) {
        let speedup_from_baseline = baseline_latency / self.avg_latency_micros;
        let recommendation = if self.aggregate_speedup < 1.1 {
            "SKIP (minimal)"
        } else if self.total_memory_saved_mb < 20.0 {
            "SKIP (low savings)"
        } else if self.aggregate_speedup < 1.5 {
            "MAYBE (balance)"
        } else if self.aggregate_speedup < 2.0 {
            "YES (good)"
        } else {
            "YES! (excellent)"
        };

        println!(
            "{:<15} {:<15} {:<12} {:<12} {:<12} {:<12} {:<15}",
            self.variant_name,
            format!("{:.2} μs", self.avg_latency_micros),
            format!("{:.2}x", speedup_from_baseline),
            format!("{:.2}x", self.avg_compression_ratio),
            format!("{:.1}MB", self.total_memory_saved_mb),
            format!(
                "{:.1}/{:.1}",
                self.min_latency_micros, self.max_latency_micros
            ),
            recommendation
        );
    }
}

fn main() {
    println!("╔════════════════════════════════════════════════════════════════════╗");
    println!("║  Phi-3-mini Low-Rank FFN Benchmark: Latency vs Accuracy Tradeoff  ║");
    println!("╚════════════════════════════════════════════════════════════════════╝\n");

    println!("Configuration:");
    println!("  - Model: Phi-3-mini-4k (hidden=3072, intermediate=8192, layers=32)");
    println!(
        "  - Iterations: {} (+ {} warmup per variant)",
        ITERATIONS, WARMUP_ITERS
    );
    println!("  - Input: deterministic (sin-based for reproducibility)\n");

    // Benchmark all variants
    println!("Running benchmarks...");

    print!("  Standard FFN... ");
    std::io::Write::flush(&mut std::io::stdout()).unwrap();
    let standard_benches = bench_standard();
    println!("done");

    print!("  Variant A (75% LR)... ");
    std::io::Write::flush(&mut std::io::stdout()).unwrap();
    let variant_a_benches = bench_variant_a();
    println!("done");

    print!("  Variant B (50% LR)... ");
    std::io::Write::flush(&mut std::io::stdout()).unwrap();
    let variant_b_benches = bench_variant_b();
    println!("done");

    print!("  Variant C (Selective)... ");
    std::io::Write::flush(&mut std::io::stdout()).unwrap();
    let variant_c_benches = bench_variant_c();
    println!("done\n");

    // Compute aggregate statistics
    let standard_stats = AggregateStats::from_benches("Standard", &standard_benches);
    let variant_a_stats = AggregateStats::from_benches("75% LR (A)", &variant_a_benches);
    let variant_b_stats = AggregateStats::from_benches("50% LR (B)", &variant_b_benches);
    let variant_c_stats = AggregateStats::from_benches("Selective (C)", &variant_c_benches);

    // Display comparison table
    println!("╔════════════════════════════════════════════════════════════════════╗");
    println!("║                    AGGREGATE RESULTS (32 layers)                   ║");
    println!("╚════════════════════════════════════════════════════════════════════╝");

    AggregateStats::display_header();
    standard_stats.display(standard_stats.avg_latency_micros);
    variant_a_stats.display(standard_stats.avg_latency_micros);
    variant_b_stats.display(standard_stats.avg_latency_micros);
    variant_c_stats.display(standard_stats.avg_latency_micros);

    println!("\n╔════════════════════════════════════════════════════════════════════╗");
    println!("║                      PER-LAYER BREAKDOWN                           ║");
    println!("╚════════════════════════════════════════════════════════════════════╝\n");

    println!("Variant A (75% Intermediate):");
    for bench in variant_a_benches.iter().step_by(8) {
        println!(
            "  Layer {:2}: m={:4} | latency={:6.2} μs | speedup={:5.2}x | mem_save={:6.1}MB",
            bench.layer_idx,
            bench.intermediate_dim,
            bench.latency_micros,
            bench.metrics.speedup_factor,
            bench.metrics.memory_savings() as f64 / 1e6
        );
    }

    println!("\nVariant B (50% Intermediate):");
    for bench in variant_b_benches.iter().step_by(8) {
        println!(
            "  Layer {:2}: m={:4} | latency={:6.2} μs | speedup={:5.2}x | mem_save={:6.1}MB",
            bench.layer_idx,
            bench.intermediate_dim,
            bench.latency_micros,
            bench.metrics.speedup_factor,
            bench.metrics.memory_savings() as f64 / 1e6
        );
    }

    println!("\nVariant C (Selective per-layer):");
    for bench in variant_c_benches.iter().step_by(8) {
        let tier = if bench.layer_idx < 11 {
            "early"
        } else if bench.layer_idx < 22 {
            "mid"
        } else {
            "late"
        };
        println!(
            "  Layer {:2} ({:4}): m={:4} | latency={:6.2} μs | speedup={:5.2}x | mem_save={:6.1}MB",
            bench.layer_idx,
            tier,
            bench.intermediate_dim,
            bench.latency_micros,
            bench.metrics.speedup_factor,
            bench.metrics.memory_savings() as f64 / 1e6
        );
    }

    // Summary and recommendation
    println!("\n╔════════════════════════════════════════════════════════════════════╗");
    println!("║                    ANALYSIS & RECOMMENDATION                       ║");
    println!("╚════════════════════════════════════════════════════════════════════╝\n");

    println!("Speedup Summary (aggregated across 32 layers):");
    println!("  Standard:    1.00x (baseline)");
    println!(
        "  Variant A:   {:.2}x ({:.1} MB saved)",
        variant_a_stats.aggregate_speedup, variant_a_stats.total_memory_saved_mb
    );
    println!(
        "  Variant B:   {:.2}x ({:.1} MB saved)",
        variant_b_stats.aggregate_speedup, variant_b_stats.total_memory_saved_mb
    );
    println!(
        "  Variant C:   {:.2}x ({:.1} MB saved)",
        variant_c_stats.aggregate_speedup, variant_c_stats.total_memory_saved_mb
    );

    println!("\nKey Findings:");
    println!(
        "  1. Variant A (75% intermediate) provides good latency reduction ({:.0}%) with",
        (1.0 - variant_a_stats.avg_latency_micros / standard_stats.avg_latency_micros) * 100.0
    );
    println!(
        "     minimal weight storage overhead ({:.1} MB total saved).",
        variant_a_stats.total_memory_saved_mb
    );

    println!(
        "  2. Variant B (50% intermediate) achieves highest speedup ({:.2}x) but requires",
        variant_b_stats.aggregate_speedup
    );
    println!("     verification that accuracy loss is acceptable (<2% on typical benchmarks).");

    println!(
        "  3. Variant C (selective per-layer) balances speedup ({:.2}x) and memory",
        variant_c_stats.aggregate_speedup
    );
    println!("     efficiency by preserving early layer capacity (likely best for");
    println!("     semantic fidelity on MMLU/HumanEval).");

    println!(
        "\n✓ Recommendation: {}",
        if variant_c_stats.aggregate_speedup > 1.7 {
            "Deploy Variant C (Selective) in production."
        } else if variant_a_stats.aggregate_speedup > 1.2 {
            "Start with Variant A, evaluate on MMLU 5-shot if accuracy < 0.5% loss."
        } else {
            "Low-rank FFN not recommended for this model (speedup < 1.2x)."
        }
    );

    println!("\nNext steps:");
    println!("  1. Evaluate accuracy on MMLU 5-shot (1000+ samples) for each variant");
    println!("  2. Measure end-to-end latency (prefill + decode) on representative prompts");
    println!("  3. Profile KV cache memory savings when deployed across distributed layers");
    println!("  4. Consider fine-tuning low-rank weights for variant C if accuracy loss > 0.5%");
}
